SELECT fiscal_year_id, budget_estimate, actual_expenditure
FROM budget_allocations
WHERE project_id = 1;

SELECT project_id, forecast_year, projected_budget
FROM budget_forecasts
WHERE forecast_status = 'approved';

SELECT project_name
FROM modernization_projects
ORDER BY project_name;

SELECT project_name, project_status
FROM modernization_projects
WHERE project_status = 'in_progress';

SELECT SUM(expenditure_amount) AS total_expenditure
FROM expenditure_reports
WHERE project_id = 1;

SELECT project_name
FROM modernization_projects
ORDER BY project_name;

SELECT COUNT(*) AS completed_projects
FROM modernization_projects
WHERE project_status = 'completed';

SELECT project_name, description
FROM modernization_projects
ORDER BY project_status, project_name;
